 68→    @Override
 69→    public String createSpaceNodeMigrationTask(List<TreeNode<SpaceNodeVo>> spaceNodeTree, String email, String targetSpaceId, String sourceSpaceId, List<SpaceAppRelVo> sourceSpaceApps) {
 70→        try {
 71→            List<SpaceNodeTreeNode> grpcTreeNodes = grpcMapper.toGrpcSpaceNodeTreeNodes(spaceNodeTree);
 72→            List<SpaceAppRel> grpcSpaceApps = grpcMapper.toGrpcSpaceAppRels(sourceSpaceApps);
 73→
 74→            CreateSpaceNodeMigrationTaskRequest request = CreateSpaceNodeMigrationTaskRequest.newBuilder()
 75→                    .addAllSpaceNodeTree(grpcTreeNodes)
 76→                    .setEmail(email)
 77→                    .setTargetSpaceId(targetSpaceId)
 78→                    .setSourceSpaceId(sourceSpaceId)
 79→                    .addAllSourceSpaceApps(grpcSpaceApps)
 80→                    .build();
 81→            
 82→            CreateSpaceNodeMigrationTaskResult result = collabspacePrivateStub.createSpaceNodeMigrationTask(request);
 83→            
 84→            log.info("createSpaceNodeMigrationTask success: taskId={}, email={}, targetSpaceId={}, sourceSpaceId={}, treeSize={}", 
 85→                    result.getTaskId(), email, targetSpaceId, sourceSpaceId, spaceNodeTree.size());
 86→            
 87→            return result.getTaskId();
 88→        } catch (StatusRuntimeException e) {
 89→            log.error("grpc createSpaceNodeMigrationTask error: email={}, targetSpaceId={}", email, targetSpaceId, e);
 90→            throw new RuntimeException("创建迁移任务失败", e);
 91→        }
 92→    }
