241→    private List<AnnouncementEntity> transAnnouncementEntity(List<GetListAnnouncementVo> voList) {
242→        List<AnnouncementEntity> list = new ArrayList<>();
243→        // 此处需要通过邮箱反向查出creatorId和creatorName
244→        List<String> emailList = voList.stream().map(GetListAnnouncementVo::getCreatorEmail).toList();
245→        Map<String, UserSimpleInfoVo> userMap = new HashMap<>();
246→        if (!voList.isEmpty()){
247→            List<UserSimpleInfoVo> userList = apitableGrpcClientServiceImpl.getUserByEmails(emailList);
248→            userMap = userList.stream().collect(Collectors.toMap(
249→                    UserSimpleInfoVo::getEmail,  // key: 邮箱
250→                    user -> user,                // value: 用户对象本身
251→                    (existing, replacement) -> existing
252→            ));
253→        }
254→        for (GetListAnnouncementVo vo : voList) {
255→            AnnouncementEntity announcementEntity = new AnnouncementEntity();
256→            announcementEntity.setId(vo.getId());
257→            announcementEntity.setIsPopup(vo.getIsPopup());
258→            announcementEntity.setContent(vo.getContent());
259→            announcementEntity.setTitle(vo.getTitle());
260→            announcementEntity.setStatus(vo.getStatus());
261→            announcementEntity.setPublishTime(vo.getPublishTime());
262→            announcementEntity.setCreatedAt(LocalDateTime.now());
263→            announcementEntity.setUpdatedAt(LocalDateTime.now());
264→            UserSimpleInfoVo user = userMap.get(vo.getCreatorEmail());
265→            if (user != null) {
266→                announcementEntity.setCreatorId(user.getId());
267→                announcementEntity.setCreatorName(user.getNickName());
268→            }
269→            else {
270→                // 不存在给个默认值
271→                announcementEntity.setCreatorId(-1L);
272→                announcementEntity.setCreatorName("靖禾");
273→            }
274→            list.add(announcementEntity);
275→        }
276→        return list;
277→    }
