279→    @Override
280→    public List<SpaceWithNodeVo> listManagedSpaceDataSheetMirror(Long userId) {
281→
282→        UserSimpleInfoVo userById = apitableGrpcClientServiceImpl.getUserById(userId);
283→        if(null==userById||StringUtils.isEmpty(userById.getEmail())){
284→            return Collections.emptyList();
285→        }
286→
287→        String email = userById.getEmail();
288→        try {
289→
290→            ListManagedSpaceDataSheetRequest request =
291→                    ListManagedSpaceDataSheetRequest.newBuilder().setEmail(email).build();
292→
293→            ListManagedSpaceDataSheetResponse response = collabspaceMirrorStub
294→                    .listManagedSpaceDataSheet(request);
295→
296→            return spaceGrpcConverter.fromGrpcResponse(response);
297→
298→        } catch (StatusRuntimeException e) {
299→            log.error("gRPC 调用失败: email={}, code={}, description={}",
300→                    email, e.getStatus().getCode(), e.getStatus().getDescription(), e);
301→
302→            return switch (e.getStatus().getCode()) {
303→                case DEADLINE_EXCEEDED -> throw new RuntimeException("gRPC 请求超时", e);
304→                case UNAVAILABLE -> throw new RuntimeException("gRPC 服务不可用", e);
305→                case UNAUTHENTICATED -> throw new RuntimeException("用户未认证", e);
306→                case INVALID_ARGUMENT ->
307→                        throw new IllegalArgumentException("请求参数错误: " + e.getStatus().getDescription(), e);
308→                case NOT_FOUND -> {
309→                    log.info("未找到 email 对应的用户: {}", email);
310→                    yield Collections.emptyList();
311→                }
312→                default -> throw new RuntimeException("gRPC 调用失败: " + e.getStatus().getDescription(), e);
313→            };
314→
315→        } catch (Exception e) {
316→            log.error("gRPC 客户端未知错误, email={}", email, e);
317→            return Collections.emptyList();
318→        }
319→    }
320→
