336→    private void saveNewNodeTree(List<TreeNode<SpaceNodeVo>> originalTree, String spaceId, Map<String, String> nodeIdMapping, Long userId) {
337→        if (originalTree == null || originalTree.isEmpty()) {
338→            log.info("No tree nodes to save for space: {}", spaceId);
339→            return;
340→        }
341→
342→        log.info("Starting to save new node tree for space: {}, total original nodes: {}", spaceId, originalTree.size());
343→
344→        for (TreeNode<SpaceNodeVo> node : originalTree) {
345→            Long parentId = ROOT_PARENT_ID;
346→            if (spaceId.equals(node.getData().getSpaceId())) {
347→                // 同空间站复制在原父节点下
