357→    private void saveNodeAndChildren(TreeNode<SpaceNodeVo> node, String spaceId, Map<String, String> nodeIdMapping, Long parentId, Long userId) {
358→        SpaceNodeVo spaceNodeVo = node.getData();
359→        String oldNodeId = spaceNodeVo.getAppSpaceNodeId();
360→        String newNodeId = nodeIdMapping.get(oldNodeId);
361→
362→        if (Objects.equals(spaceNodeVo.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
363→            newNodeId = "";
364→        }
365→
366→        if (newNodeId == null) {
367→            log.error("No mapping found for node: {}", oldNodeId);
368→            return;
369→        }
370→
371→        // todo:这里的序号没有考虑并发问题，如有需使用分布式锁
372→        Integer count = nodeInstancesManager.getCountByOriginId(node.getData().getId());
373→        String name = node.getData().getName() +  "的副本" ;
374→        if (count > 0){
375→            name = name + "(" + count + ")";
376→        }
377→
378→        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
379→                .appSpaceNodeId(newNodeId)
380→                .name(name)
381→                .type(spaceNodeVo.getType())
382→                .description(spaceNodeVo.getDescription())
383→                .spaceId(spaceId)
384→                .createdBy(userId)
385→                .updatedBy(userId)
386→                .build();
387→
388→        spaceNodeService.save(spaceNodeEntity);
389→
390→        // 补充副本关系
391→        nodeInstancesManager.createInstance(node.getData().getId(), spaceNodeEntity.getId(), 0);
392→        NodeEntity nodeEntity = treeNodeTemplate.addNode(parentId, spaceId, spaceNodeEntity.getId(), SpaceNodeEntity.class);
393→        log.info("migrate node, id: {}, appSpaceNodeId: {}, name: {}, parentId",spaceNodeEntity.getId(),spaceNodeEntity.getAppSpaceNodeId(),spaceNodeEntity.getName());
394→
395→        if (node.getChildren() != null && !node.getChildren().isEmpty()) {
396→            for (TreeNode<SpaceNodeVo> child : node.getChildren()) {
397→                saveNodeAndChildren(child, spaceId, nodeIdMapping, nodeEntity.getId(), userId);
398→            }
399→        }
